#include <stdint.h>

#define EXTI9_5_IRQ_NO 23
#define TIM2_IRQ_NO 28

volatile uint32_t adc_value = 0;

volatile uint32_t mode = 0;

volatile uint32_t timer_flag = 0;

/* UART Send Function */

void UART_SendChar(char ch)
{
    uint32_t USART2_BASE_ADDR = 0x40004400U;

    uint32_t* USART_SR = (uint32_t*)(USART2_BASE_ADDR + 0x00U);

    uint32_t* USART_DR = (uint32_t*)(USART2_BASE_ADDR + 0x04U);

    while(!(*USART_SR & (1 << 7)));

    *USART_DR = ch;
}

/* UART Send String */

void UART_SendString(char* str)
{
    while(*str)
    {
        UART_SendChar(*str++);
    }
}

/* Simple Integer to UART */

void UART_SendNumber(uint32_t num)
{
    char buffer[10];

    int i = 0;

    if(num == 0)
    {
        UART_SendChar('0');
        return;
    }

    while(num > 0)
    {
        buffer[i++] = (num % 10) + '0';

        num /= 10;
    }

    for(int j = i - 1; j >= 0; j--)
    {
        UART_SendChar(buffer[j]);
    }
}

