/* ---------------------------------------------------- */
/* GPIO Interrupt Handler                               */
/* ---------------------------------------------------- */

void EXTI9_5_IRQHandler(void)
{
    uint32_t EXTI_BASE_ADDR = 0x40013C00U;

    uint32_t* EXTI_PR = (uint32_t*)(EXTI_BASE_ADDR + 0x14U);

    if(*EXTI_PR & (1 << 7))
    {
        mode ^= 1;

        *EXTI_PR = (1 << 7);
    }
}

/* ---------------------------------------------------- */
/* Timer Interrupt Handler                              */
/* ---------------------------------------------------- */

void TIM2_IRQHandler(void)
{
    uint32_t TIM2_BASE_ADDR = 0x40000000U;

    uint32_t* TIM2_SR = (uint32_t*)(TIM2_BASE_ADDR + 0x10U);

    if(*TIM2_SR & (1 << 0))
    {
        timer_flag = 1;

        *TIM2_SR &= ~(1 << 0);
    }
}
